# Layered PII detector: structural + regex + checksum
import re

STRUCTURAL_KEYS = {"email", "phone", "ssn", "prompt", "tool_args"}
EMAIL = re.compile(r"[\w.+-]+@[\w-]+\.[\w.-]+")
CARD = re.compile(r"\b(?:\d[ -]*?){13,16}\b")

def luhn_ok(number: str) -> bool:
    digits = [int(c) for c in number if c.isdigit()]
    checksum, parity = 0, len(digits) % 2
    for i, d in enumerate(digits):
        if i % 2 == parity:
            d *= 2
            if d > 9:
                d -= 9
        checksum += d
    return checksum % 10 == 0

def scrub_text(text: str) -> str:
    text = EMAIL.sub("<EMAIL>", text)
    def card_sub(m):
        return "<CARD>" if luhn_ok(m.group()) else m.group()
    return CARD.sub(card_sub, text)

# Ingest transform: structural mask + content scrub + NER
def scrub_event(event: dict, ner) -> dict:
    out = {}
    for key, value in event.items():
        if key in STRUCTURAL_KEYS:
            out[key] = "<redacted>"
        elif isinstance(value, str):
            scrubbed = scrub_text(value)
            # NER pass for names/locations without fixed format
            for ent in ner(scrubbed):
                if ent.label in ("PERSON", "GPE", "ORG"):
                    scrubbed = scrubbed.replace(ent.text, f"<{ent.label}>")
            out[key] = scrubbed
        else:
            out[key] = value
    return out

# Wired into the collector so no service can bypass it
def on_ingest(batch, ner):
    return [scrub_event(e, ner) for e in batch]

# Offline canary scan over stored logs to find missed PII
def canary_scan(sampled_events, strict_detector):
    leaks = []
    for ev in sampled_events:
        for key, value in ev.items():
            if not isinstance(value, str):
                continue
            hits = strict_detector(value)   # slower, higher recall
            real = [h for h in hits if "<" not in h.text]  # not already a placeholder
            if real:
                leaks.append({"event_id": ev["id"], "field": key,
                              "types": sorted({h.label for h in real})})
    return leaks

def triage(leaks):
    # 1) delete the leaked values; 2) feed detector improvements
    for leak in leaks:
        schedule_targeted_deletion(leak["event_id"], leak["field"])
        record_detector_gap(leak["types"])   # expands regex / NER training
    return {"leaks": len(leaks),
            "gap_types": sorted({t for l in leaks for t in l["types"]})}
